   183→/**
   184→ * Folder Sidebar Component (Simplified for MVP)
   185→ */
   186→const FolderSidebar: React.FC<{
   187→  activeTags: string[];
   188→  onAddTag: (tag: string) => void;
   189→  onRemoveTag: (tag: string) => void;
   190→  onClearAllTags: () => void;
   191→  onOpenTagManager: () => void;
   192→}> = ({ activeTags, onAddTag, onRemoveTag, onClearAllTags, onOpenTagManager }) => {
   193→  // Get raw folders object (stable reference unless folders change)
   194→  const foldersObj = useFoldersStore((state) => state.folders);
   195→  const activeFolderId = useFoldersStore((state) => state.activeFolderId);
   196→  const setActiveFolder = useFoldersStore((state) => state.setActiveFolder);
   197→  const createFolder = useFoldersStore((state) => state.createFolder);
   198→  const deleteFolder = useFoldersStore((state) => state.deleteFolder);
   199→  const updateFolder = useFoldersStore((state) => state.updateFolder);
   200→  const notesObj = useNotesStore((state) => state.notes);
   201→  const searchNotes = useNotesStore((state) => state.searchNotes);
   202→
   203→  // Dialog state
   204→  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
   205→  const [renameDialogOpen, setRenameDialogOpen] = useState(false);
   206→  const [selectedFolderId, setSelectedFolderId] = useState<string | null>(null);
   207→  const [selectedFolderName, setSelectedFolderName] = useState('');
   208→
   209→  // Search state
   210→  const [searchQuery, setSearchQuery] = useState('');
   211→  const searchInputRef = useRef<HTMLInputElement>(null);
   212→
   213→  // Keyboard shortcut for search (Cmd+K)
   214→  useEffect(() => {
   215→    const handleKeyDown = (e: KeyboardEvent) => {
   216→      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
   217→        e.preventDefault();
   218→        searchInputRef.current?.focus();
   219→      }
   220→    };
   221→
   222→    window.addEventListener('keydown', handleKeyDown);
   223→    return () => window.removeEventListener('keydown', handleKeyDown);
   224→  }, []);
   225→
   226→  // Get tree structure for nested folders
   227→  const getTree = useFoldersStore((state) => state.getTree);
   228→  const toggleExpanded = useFoldersStore((state) => state.toggleExpanded);
   229→  const expandedFolderIds = useFoldersStore((state) => state.expandedFolderIds);
   230→
   231→  const folderTree = useMemo(() => getTree(), [foldersObj, getTree]);
   232→
   233→  // Get note count for a folder
   234→  const getFolderNoteCount = (folderId: string) => {
   235→    return Object.values(notesObj).filter(note => note.folderId === folderId).length;
   236→  };
   237→
   238→  // Handle folder deletion
   239→  const handleDeleteFolder = (folderId: string, folderName: string) => {
   240→    setSelectedFolderId(folderId);
   241→    setSelectedFolderName(folderName);
   242→    setDeleteDialogOpen(true);
   243→  };
   244→
   245→  const confirmDeleteFolder = () => {
   246→    if (!selectedFolderId) return;
   247→
   248→    // Save folder and notes for undo
   249→    const folderToDelete = foldersObj[selectedFolderId];
   250→    if (!folderToDelete) {
   251→      log.warn('Folder not found', { folderId: selectedFolderId });
   252→      return;
   253→    }
   254→
   255→    const notesToDelete = Object.values(notesObj).filter(note => note.folderId === selectedFolderId);
   256→    const noteCount = notesToDelete.length;
   257→
   258→    // Delete all notes in this folder (without undo since folder undo will handle it)
   259→    // We need to temporarily bypass the undo system for individual notes
   260→    notesToDelete.forEach(note => {
   261→      // Call the store action directly without triggering undo
   262→      useNotesStore.setState((state) => {
   263→        const { [note.id]: deleted, ...remainingNotes } = state.notes;
   264→        return {
   265→          notes: remainingNotes,
   266→          activeNoteId: state.activeNoteId === note.id ? null : state.activeNoteId,
   267→        };
   268→      });
   269→    });
   270→
   271→    // Delete the folder
   272→    deleteFolder(selectedFolderId);
   273→
   274→    log.info(`Folder "${folderToDelete.name}" deleted`, { noteCount });
   275→
   276→    // Add undo action to restore folder AND notes
   277→    useUndoStore.getState().addUndoAction(
   278→      `Folder "${folderToDelete.name}" and ${noteCount} note(s) deleted`,
   279→      () => {
   280→        // Restore the folder
   281→        useFoldersStore.setState((state) => ({
   282→          folders: {
   283→            ...state.folders,
   284→            [folderToDelete.id]: folderToDelete,
   285→          },
   286→        }));
   287→
   288→        // Restore all notes
   289→        useNotesStore.setState((state) => {
   290→          const restoredNotes = { ...state.notes };
   291→          notesToDelete.forEach(note => {
   292→            restoredNotes[note.id] = note;
   293→          });
   294→          return {
   295→            notes: restoredNotes,
   296→          };
   297→        });
   298→
   299→        log.info(`Folder "${folderToDelete.name}" and ${noteCount} note(s) restored (undo)`);
   300→      }
   301→    );
   302→  };
   303→
   304→  // Handle folder rename
   305→  const handleRenameFolder = (folderId: string, currentName: string) => {
   306→    setSelectedFolderId(folderId);
   307→    setSelectedFolderName(currentName);
   308→    setRenameDialogOpen(true);
   309→  };
   310→
   311→  const confirmRenameFolder = (newName: string) => {
   312→    if (!selectedFolderId || !newName.trim()) return;
   313→    updateFolder(selectedFolderId, { name: newName.trim() });
   314→  };
   315→
   316→  return (
   317→    <div className="p-4 flex flex-col max-h-[40%] overflow-hidden border-b border-border-light dark:border-border-dark">
   318→      {/* Folders header */}
   319→      <div className="flex items-center justify-between mb-4 flex-shrink-0">
   320→        <h3 className="text-base font-semibold text-text-light-primary dark:text-text-dark-primary">Folders</h3>
   321→        <button
   322→          onClick={() => createFolder()}
   323→          className="text-xs px-3 h-8 bg-accent-blue hover:bg-accent-blue-hover text-white rounded transition-colors duration-150 font-medium"
   324→          title="New Folder"
   325→        >
   326→          + Folder
   327→        </button>
   328→      </div>
   329→
   330→      {/* Search Input */}
   331→      <div className="px-3 py-2">
   332→        <input
   333→          type="text"
   334→          placeholder="Search notes... (Cmd+K)"
   335→          className="w-full px-3 py-2 text-sm border border-border-light dark:border-border-dark rounded-lg
   336→                     bg-surface-light dark:bg-surface-dark
   337→                     text-text-light-primary dark:text-text-dark-primary
   338→                     placeholder-text-light-secondary dark:placeholder-text-dark-secondary
   339→                     focus:outline-none focus:ring-2 focus:ring-accent-blue transition-all"
   340→          value={searchQuery}
   341→          onChange={(e) => setSearchQuery(e.target.value)}
   342→          ref={searchInputRef}
   343→        />
   344→      </div>
   345→
   346→      {/* All Notes (root level) */}
   347→      {!searchQuery.trim() && (
   348→        <button
   349→          onClick={() => setActiveFolder(null)}
   350→          className={`w-full text-left px-3 h-8 rounded-lg transition-colors mb-1 flex-shrink-0 flex items-center gap-2 text-base ${
   351→            activeFolderId === null
   352→              ? 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary font-medium'
   353→              : 'hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary'
   354→          }`}
   355→        >
   356→          <FolderOpen className="w-4 h-4" />
   357→          All Notes
   358→        </button>
   359→      )}
   360→
   361→      {/* Search Results OR Folder list */}
   362→      {searchQuery.trim() ? (
   363→        /* Search Results */
   364→        <div className="px-3 overflow-y-auto flex-1">
   365→          <h3 className="text-sm font-semibold text-text-light-secondary dark:text-text-dark-secondary mb-2">
   366→            {searchNotes(searchQuery).length} results for "{searchQuery}"
   367→          </h3>
   368→          <div className="space-y-2">
   369→            {searchNotes(searchQuery).map((note) => (
   370→              <div
   371→                key={note.id}
   372→                onClick={() => {
   373→                  setSearchQuery(''); // Clear search
   374→                  // Note will be selected via the NotesList component
   375→                }}
   376→                className="p-3 rounded-lg cursor-pointer hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors"
   377→              >
   378→                <div className="font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
   379→                  {note.title || 'Untitled'}
   380→                </div>
   381→                <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary line-clamp-2">
   382→                  {note.contentText?.slice(0, 150)}...
   383→                </div>
   384→                <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
   385→                  {new Date(note.updatedAt).toLocaleDateString()}
   386→                </div>
   387→              </div>
   388→            ))}
   389→            {searchNotes(searchQuery).length === 0 && (
   390→              <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary text-center py-8">
   391→                No notes found for "{searchQuery}"
   392→              </div>
   393→            )}
   394→          </div>
   395→        </div>
   396→      ) : (
   397→        /* Folder tree - Scrollable */
   398→        <div className="space-y-1 overflow-y-auto flex-1">
   399→          {folderTree.map((node) => (
   400→            <FolderTreeNode
   401→              key={node.id}
   402→              node={node}
   403→              depth={0}
   404→              activeFolderId={activeFolderId}
   405→              expandedFolderIds={expandedFolderIds}
   406→              onSelect={setActiveFolder}
   407→              onToggleExpanded={toggleExpanded}
   408→              onDelete={handleDeleteFolder}
   409→              onRename={handleRenameFolder}
   410→              getFolderNoteCount={getFolderNoteCount}
   411→            />
   412→          ))}
   413→
   414→          {/* Empty state */}
   415→          {folderTree.length === 0 && (
   416→            <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary text-center py-4">
   417→              No folders yet
   418→            </div>
   419→          )}
   420→        </div>
   421→      )}
   422→
   423→      {/* Tag Filter Section */}
   424→      <div className="px-4 py-3 border-t border-border-light dark:border-border-dark">
   425→        <TagFilter
   426→          activeTags={activeTags}
   427→          onAddTag={onAddTag}
   428→          onRemoveTag={onRemoveTag}
   429→          onClearAll={onClearAllTags}
   430→        />
   431→        <button
   432→          onClick={onOpenTagManager}
   433→          className="w-full mt-3 px-3 py-2 text-xs font-medium rounded border border-border-light dark:border-border-dark hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary transition-colors"
   434→        >
   435→          Manage Tags
   436→        </button>
   437→      </div>
   438→
   439→      {/* Delete Folder Confirmation Dialog */}
   440→      <ConfirmDialog
   441→        isOpen={deleteDialogOpen}
   442→        onClose={() => setDeleteDialogOpen(false)}
   443→        onConfirm={confirmDeleteFolder}
   444→        title="Delete Folder"
   445→        message={`Delete folder "${selectedFolderName}"? This will also delete ${selectedFolderId ? getFolderNoteCount(selectedFolderId) : 0} note(s) inside.`}
   446→        confirmText="Delete"
   447→        variant="danger"
   448→      />
   449→
   450→      {/* Rename Folder Prompt Dialog */}
   451→      <PromptDialog
   452→        isOpen={renameDialogOpen}
   453→        onClose={() => setRenameDialogOpen(false)}
   454→        onConfirm={confirmRenameFolder}
   455→        title="Rename Folder"
   456→        message="Enter a new name for this folder:"
   457→        defaultValue={selectedFolderName}
   458→        placeholder="Folder name"
   459→        confirmText="Rename"
   460→      />
   461→    </div>
   462→  );
   463→};
