   647→
   648→          {/* Meta */}
   649→          <div className="flex items-center justify-between text-xs text-text-light-secondary dark:text-text-dark-secondary">
   650→            <span>{formatDate(note.updatedAt)}</span>
   651→          </div>
   652→        </div>
   653→
   654→        {/* Selection checkbox (if in selection mode) */}
   655→        {isSelectionMode && onToggleSelection && (
   656→          <div className="shrink-0 ml-2" onClick={(e) => e.stopPropagation()}>
   657→            <input
   658→              type="checkbox"
   659→              checked={isSelected}
   660→              onChange={() => onToggleSelection(note.id)}
   661→              className="w-4 h-4 rounded border-border-light dark:border-border-dark cursor-pointer"
   662→              aria-label={`Select note ${note.title}`}
