   686→/**
   687→ * Notes List Component
   688→ */
   689→const NotesList: React.FC<{ activeTags: string[] }> = ({ activeTags }) => {
   690→  const activeFolderId = useFoldersStore((state) => state.activeFolderId);
   691→  // Get raw notes and store config (stable references)
   692→  const notesObj = useNotesStore((state) => state.notes);
   693→  const sortConfig = useNotesStore((state) => state.sortConfig);
   694→  const filter = useNotesStore((state) => state.filter);
   695→  const activeNoteId = useNotesStore((state) => state.activeNoteId);
   696→  const createNote = useNotesStore((state) => state.createNote);
   697→  const bulkAddTag = useNotesStore((state) => state.bulkAddTag);
   698→  const bulkRemoveTag = useNotesStore((state) => state.bulkRemoveTag);
   699→
   700→  // Bulk operations state
   701→  const [selectionMode, setSelectionMode] = useState(false);
   702→  const [selectedNoteIds, setSelectedNoteIds] = useState<Set<string>>(new Set());
   703→  const [bulkTagDialogOpen, setBulkTagDialogOpen] = useState(false);
   704→  const [bulkTagAction, setBulkTagAction] = useState<'add' | 'remove' | null>(null);
   705→  const [bulkTagValue, setBulkTagValue] = useState('');
   706→
   707→  // Bulk operations handlers
   708→  const toggleSelectionMode = () => {
   709→    setSelectionMode(!selectionMode);
   710→    if (selectionMode) {
   711→      setSelectedNoteIds(new Set());
   712→    }
   713→  };
   714→
   715→  const toggleNoteSelection = (noteId: string) => {
   716→    setSelectedNoteIds((prev) => {
   717→      const next = new Set(prev);
   718→      if (next.has(noteId)) {
   719→        next.delete(noteId);
   720→      } else {
   721→        next.add(noteId);
   722→      }
   723→      return next;
   724→    });
   725→  };
   726→
   727→  const selectAll = () => {
   728→    const allIds = notes.map((n) => n.id);
   729→    setSelectedNoteIds(new Set(allIds));
   730→  };
   731→
   732→  const deselectAll = () => {
   733→    setSelectedNoteIds(new Set());
   734→  };
   735→
   736→  const handleBulkAddTag = () => {
   737→    setBulkTagAction('add');
   738→    setBulkTagDialogOpen(true);
   739→  };
   740→
   741→  const handleBulkRemoveTag = () => {
   742→    setBulkTagAction('remove');
   743→    setBulkTagDialogOpen(true);
   744→  };
   745→
   746→  const confirmBulkTagAction = (value: string) => {
   747→    if (!value.trim() || selectedNoteIds.size === 0) return;
   748→
   749→    if (bulkTagAction === 'add') {
   750→      bulkAddTag(Array.from(selectedNoteIds), value.trim());
   751→    } else if (bulkTagAction === 'remove') {
   752→      bulkRemoveTag(Array.from(selectedNoteIds), value.trim());
   753→    }
   754→
   755→    // Clear selection and close dialog
   756→    setBulkTagDialogOpen(false);
   757→    setBulkTagValue('');
   758→    setSelectedNoteIds(new Set());
   759→    setSelectionMode(false);
   760→  };
   761→
   762→  // Compute filtered/sorted notes with useMemo
   763→  const notes = useMemo(() => {
   764→    // Filter by folder
   765→    // If activeFolderId is null, show ALL notes (not just notes with null folderId)
   766→    let filtered = activeFolderId === null
   767→      ? Object.values(notesObj) // Show all notes when "All Notes" is selected
   768→      : Object.values(notesObj).filter((note) => note.folderId === activeFolderId);
   769→
   770→    // Filter by tags (AND logic - note must have ALL selected tags or their children)
   771→    if (activeTags.length > 0) {
   772→      filtered = filtered.filter((note) =>
   773→        activeTags.every((filterTag) =>
   774→          note.tags.some((noteTag) => tagMatchesFilter(noteTag, filterTag))
   775→        )
   776→      );
   777→    }
   778→
   779→    // Apply filter (archived, pinned, favorites, etc.)
   780→    switch (filter) {
   781→      case 'favorites':
   782→        filtered = filtered.filter((note) => note.isFavorite);
   783→        break;
   784→      case 'pinned':
   785→        filtered = filtered.filter((note) => note.isPinned);
   786→        break;
   787→      case 'archived':
   788→        filtered = filtered.filter((note) => note.isArchived);
   789→        break;
   790→      case 'unarchived':
   791→        filtered = filtered.filter((note) => !note.isArchived);
   792→        break;
   793→    }
   794→
   795→    // Sort notes
   796→    const sorted = [...filtered].sort((a, b) => {
   797→      let comparison = 0;
   798→      switch (sortConfig.field) {
   799→        case 'title':
   800→          comparison = a.title.localeCompare(b.title);
   801→          break;
   802→        case 'createdAt':
   803→          comparison = a.createdAt.getTime() - b.createdAt.getTime();
   804→          break;
   805→        case 'updatedAt':
   806→          comparison = a.updatedAt.getTime() - b.updatedAt.getTime();
   807→          break;
   808→      }
   809→      return sortConfig.order === 'asc' ? comparison : -comparison;
   810→    });
   811→
   812→    // Always pin pinned notes to top
   813→    return sorted.sort((a, b) => {
   814→      if (a.isPinned && !b.isPinned) return -1;
   815→      if (!a.isPinned && b.isPinned) return 1;
   816→      return 0;
   817→    });
   818→  }, [notesObj, activeFolderId, sortConfig, filter, activeTags]);
   819→
   820→  return (
   821→    <div className="flex-1 overflow-y-auto">
   822→      <div className="bento-card p-4 m-3">
   823→        {/* Notes header */}
   824→        <div className="flex items-center justify-between mb-4">
   825→          <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
   826→            Notes ({notes.length})
   827→          </h3>
   828→          <div className="flex items-center gap-2">
   829→            <button
   830→              onClick={toggleSelectionMode}
   831→              className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-all duration-200 ${
   832→                selectionMode
   833→                  ? 'bg-accent-cyan/20 dark:bg-accent-magenta/20 text-accent-cyan dark:text-accent-magenta'
   834→                  : 'border border-border-light dark:border-border-dark text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
   835→              }`}
   836→            >
   837→              {selectionMode ? 'Cancel Selection' : 'Select Notes'}
   838→            </button>
   839→            <button
   840→              onClick={() => createNote({ folderId: activeFolderId })}
   841→              className="px-3 py-1.5 bg-gradient-button-primary text-white rounded-lg hover:shadow-glow-magenta transition-all duration-200 text-sm font-medium"
   842→            >
   843→              + New Note
   844→            </button>
   845→          </div>
   846→        </div>
   847→
   848→        {/* Bulk Operations Toolbar */}
   849→        {selectionMode && selectedNoteIds.size > 0 && (
   850→          <div className="mb-4 p-3 rounded-lg bg-accent-blue/10 dark:bg-accent-blue/20 border border-accent-blue/30">
   851→            <div className="flex items-center justify-between">
   852→              <span className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
   853→                {selectedNoteIds.size} note{selectedNoteIds.size !== 1 ? 's' : ''} selected
   854→              </span>
   855→              <div className="flex items-center gap-2">
   856→                <button
   857→                  onClick={selectAll}
   858→                  className="px-2 py-1 text-xs font-medium rounded border border-border-light dark:border-border-dark hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors text-text-light-secondary dark:text-text-dark-secondary"
   859→                >
   860→                  Select All
   861→                </button>
   862→                <button
   863→                  onClick={deselectAll}
   864→                  className="px-2 py-1 text-xs font-medium rounded border border-border-light dark:border-border-dark hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors text-text-light-secondary dark:text-text-dark-secondary"
   865→                >
   866→                  Deselect All
   867→                </button>
   868→                <button
   869→                  onClick={handleBulkAddTag}
   870→                  className="px-3 py-1 text-xs font-medium rounded bg-accent-blue text-white hover:bg-accent-blue-hover transition-colors"
   871→                >
   872→                  Add Tag
   873→                </button>
   874→                <button
   875→                  onClick={handleBulkRemoveTag}
   876→                  className="px-3 py-1 text-xs font-medium rounded bg-red-500/20 text-red-500 hover:bg-red-500/30 transition-colors"
   877→                >
   878→                  Remove Tag
   879→                </button>
   880→              </div>
   881→            </div>
   882→          </div>
   883→        )}
   884→
   885→      {/* Notes list */}
   886→      <div className="space-y-3">
   887→        {notes.map((note) => (
   888→          <NoteListItem
   889→            key={note.id}
   890→            note={note}
   891→            isActive={note.id === activeNoteId}
   892→            isSelectionMode={selectionMode}
   893→            isSelected={selectedNoteIds.has(note.id)}
   894→            onToggleSelection={toggleNoteSelection}
   895→          />
   896→        ))}
   897→      </div>
   898→
   899→      {/* Empty state */}
   900→      {notes.length === 0 && (
   901→        <div className="text-center py-16 animate-fade-in">
   902→          <div className="flex justify-center mb-6">
   903→            <div className="p-6 bg-gradient-to-br from-accent-magenta/10 to-accent-cyan/10 dark:from-accent-cyan/10 dark:to-accent-magenta/10 rounded-2xl">
   904→              <FileText className="w-16 h-16 text-accent-cyan dark:text-accent-magenta" />
   905→            </div>
   906→          </div>
   907→          <h3 className="text-2xl font-bold text-text-light-primary dark:text-text-dark-primary mb-3">
   908→            {activeTags.length > 0 ? 'No notes match these tags' : 'No notes in this folder'}
   909→          </h3>
   910→          <p className="text-text-light-secondary dark:text-text-dark-secondary mb-2 max-w-sm mx-auto">
   911→            {activeTags.length > 0
   912→              ? 'Try removing some tags or create a new note'
   913→              : 'Start capturing your thoughts, ideas, and knowledge'}
   914→          </p>
   915→          <p className="text-sm text-text-light-tertiary dark:text-text-dark-tertiary mb-6">
   916→            Tip: Use <kbd className="px-2 py-1 bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded text-xs font-mono">Cmd+N</kbd> to create notes quickly
   917→          </p>
   918→          <button
   919→            onClick={() => createNote({ folderId: activeFolderId })}
   920→            className="px-6 py-3 bg-gradient-button-primary text-white rounded-lg hover:shadow-glow-magenta transition-all duration-standard font-medium inline-flex items-center gap-2"
   921→          >
   922→            <FileText className="w-5 h-5" />
   923→            Create Your First Note
   924→          </button>
   925→        </div>
   926→      )}
   927→      </div>
   928→
   929→      {/* Bulk Tag Dialog */}
   930→      {bulkTagDialogOpen && (
   931→        <PromptDialog
   932→          isOpen={true}
   933→          onClose={() => {
   934→            setBulkTagDialogOpen(false);
   935→            setBulkTagValue('');
   936→          }}
   937→          onConfirm={confirmBulkTagAction}
   938→          title={bulkTagAction === 'add' ? 'Add Tag to Selected Notes' : 'Remove Tag from Selected Notes'}
   939→          message={
   940→            bulkTagAction === 'add'
   941→              ? `Enter tag name to add to ${selectedNoteIds.size} note${selectedNoteIds.size !== 1 ? 's' : ''}:`
   942→              : `Enter tag name to remove from ${selectedNoteIds.size} note${selectedNoteIds.size !== 1 ? 's' : ''}:`
   943→          }
   944→          defaultValue={bulkTagValue}
   945→          placeholder="Tag name"
   946→          confirmText={bulkTagAction === 'add' ? 'Add Tag' : 'Remove Tag'}
   947→        />
   948→      )}
   949→    </div>
   950→  );
   951→};
