   170→/**
   171→ * Default note values
   172→ */
   173→const createDefaultNote = (overrides?: Partial<Note>): Note => {
   174→  const now = new Date();
   175→  return {
   176→    id: uuidv4(),
   177→    folderId: null,
   178→    title: NOTE_CONSTANTS.DEFAULT_TITLE,
   179→    content: '', // Empty Lexical state
   180→    contentText: '',
   181→    tags: [],
   182→    createdAt: now,
   183→    updatedAt: now,
   184→    isPinned: false,
   185→    isArchived: false,
   186→    ...overrides,
   187→  };
   188→};
   189→
   190→/**
   191→ * Sort notes based on sort config
   192→ */
   193→const sortNotes = (notes: Note[], config: NoteSortConfig): Note[] => {
   194→  const sorted = [...notes];
   195→
   196→  sorted.sort((a, b) => {
   197→    let comparison = 0;
   198→
   199→    switch (config.field) {
   200→      case 'title':
   201→        comparison = a.title.localeCompare(b.title);
   202→        break;
   203→      case 'createdAt':
   204→        comparison = a.createdAt.getTime() - b.createdAt.getTime();
   205→        break;
   206→      case 'updatedAt':
   207→        comparison = a.updatedAt.getTime() - b.updatedAt.getTime();
   208→        break;
   209→      case 'manual':
   210→        // Manual sort - preserve order (could add sortOrder field in future)
   211→        comparison = 0;
   212→        break;
   213→    }
   214→
   215→    return config.order === 'asc' ? comparison : -comparison;
   216→  });
   217→
   218→  // Always pin pinned notes to top
   219→  return sorted.sort((a, b) => {
   220→    if (a.isPinned && !b.isPinned) return -1;
   221→    if (!a.isPinned && b.isPinned) return 1;
   222→    return 0;
   223→  });
   224→};
   225→
   226→/**
   227→ * Filter notes based on filter type
   228→ */
   229→const filterNotes = (notes: Note[], filter: NoteFilter): Note[] => {
   230→  switch (filter) {
   231→    case 'favorites':
   232→      return notes.filter((note) => note.isFavorite);
   233→    case 'pinned':
   234→      return notes.filter((note) => note.isPinned);
   235→    case 'archived':
   236→      return notes.filter((note) => note.isArchived);
   237→    case 'unarchived':
   238→      return notes.filter((note) => !note.isArchived);
   239→    case 'all':
   240→    default:
   241→      return notes;
   242→  }
   243→};
