   252→      notes: {},
   253→      activeNoteId: null,
   254→      sortConfig: {
   255→        field: 'updatedAt',
   256→        order: 'desc',
   257→      },
   258→      filter: 'unarchived',
   259→      customNoteTemplates: [],
   260→
   261→      // CRUD Operations
   262→      createNote: (params) => {
   263→        const newNote = createDefaultNote(params);
   264→        set((state) => ({
   265→          notes: {
   266→            ...state.notes,
   267→            [newNote.id]: newNote,
   268→          },
   269→          activeNoteId: newNote.id, // Auto-select new note
   270→        }));
   271→        log.debug('Note created', { id: newNote.id });
   272→        return newNote;
   273→      },
   274→
   275→      getNote: (id) => {
   276→        return get().notes[id];
   277→      },
   278→
   279→      updateNote: (id, updates) => {
   280→        const note = get().notes[id];
   281→        if (!note) {
   282→          log.warn('Note not found', { id });
   283→          return;
   284→        }
   285→
   286→        // Only update timestamp if content/title/tags actually changed
   287→        // Skip timestamp update for UI-only changes (like folderId without content change)
   288→        const shouldUpdateTimestamp =
   289→          updates.content !== undefined ||
   290→          updates.title !== undefined ||
   291→          updates.tags !== undefined;
   292→
   293→        set((state) => ({
   294→          notes: {
   295→            ...state.notes,
   296→            [id]: {
   297→              ...note,
   298→              ...updates,
   299→              ...(shouldUpdateTimestamp ? { updatedAt: new Date() } : {}),
   300→            },
   301→          },
   302→        }));
   303→        log.debug('Note updated', { id, timestampUpdated: shouldUpdateTimestamp });
   304→      },
   305→
   306→      deleteNote: (id) => {
   307→        // Save note for undo
   308→        const noteToDelete = get().notes[id];
   309→        if (!noteToDelete) {
   310→          log.warn('Note not found', { id });
   311→          return;
   312→        }
   313→
   314→        // Store the previous activeNoteId for undo
   315→        const wasActive = get().activeNoteId === id;
   316→
   317→        // Delete the note
   318→        set((state) => {
   319→          const { [id]: deleted, ...remainingNotes } = state.notes;
   320→          return {
   321→            notes: remainingNotes,
   322→            activeNoteId: state.activeNoteId === id ? null : state.activeNoteId,
   323→          };
   324→        });
   325→
   326→        log.debug('Note deleted', { id });
   327→
   328→        // Delete associated images from IndexedDB (async, fire-and-forget)
   329→        import('../services/indexedDB').then(({ indexedDBService }) => {
   330→          indexedDBService.deleteNoteImages(id).catch((err) => {
   331→            log.error('Failed to delete note images', { id, error: err });
   332→          });
   333→        });
   334→
   335→        // Add undo action
   336→        useUndoStore.getState().addUndoAction(
   337→          `Note "${noteToDelete.title}" deleted`,
   338→          () => {
   339→            // Restore the note
   340→            set((state) => ({
   341→              notes: {
   342→                ...state.notes,
   343→                [id]: noteToDelete,
   344→              },
   345→              activeNoteId: wasActive ? id : state.activeNoteId,
   346→            }));
   347→            log.debug('Note restored (undo)', { id });
   348→          }
   349→        );
   350→      },
   351→
   352→      duplicateNote: (id) => {
   353→        const original = get().notes[id];
   354→        if (!original) {
   355→          log.warn('Note not found', { id });
   356→          return null;
   357→        }
   358→
   359→        const duplicate = createDefaultNote({
   360→          ...original,
