   363→        });
   364→
   365→        set((state) => ({
   366→          notes: {
   367→            ...state.notes,
   368→            [duplicate.id]: duplicate,
   369→          },
   370→        }));
   371→
   372→        log.debug('Note duplicated', { original: id, duplicate: duplicate.id });
   373→        return duplicate;
   374→      },
