     1→/**
     2→ * Daily Notes Settings Component
     3→ *
     4→ * Provides UI for customizing daily notes feature:
     5→ * - Enable/disable daily notes
     6→ * - Date format selection (long/iso/short)
     7→ * - Template editor with variable hints
     8→ * - Folder selection for daily notes
     9→ */
    10→
    11→import React, { useState, useMemo } from 'react';
    12→import { useSettingsStore } from '../../stores/useSettingsStore';
    13→import { useFoldersStore } from '../../stores/useFoldersStore';
    14→import { FileText, Calendar, FolderOpen } from 'lucide-react';
    15→import type { DailyNotesSettings } from '../../services/dailyNotes';
    16→
    17→export const DailyNotesSettingsComponent: React.FC = () => {
    18→  const { dailyNotes, setDailyNotesSettings } = useSettingsStore();
    19→  const folders = useFoldersStore((state) => state.folders);
    20→
    21→  // Local editing state for template
    22→  const [templateDraft, setTemplateDraft] = useState(dailyNotes.template);
    23→
    24→  // Get today's date for preview
    25→  const today = useMemo(() => new Date(), []);
    26→
    27→  // Format preview based on selected format
    28→  const datePreview = useMemo(() => {
    29→    const year = today.getFullYear();
    30→    const month = today.getMonth();
    31→    const day = today.getDate();
    32→
    33→    const monthNames = [
    34→      'January', 'February', 'March', 'April', 'May', 'June',
    35→      'July', 'August', 'September', 'October', 'November', 'December'
    36→    ];
    37→
    38→    switch (dailyNotes.dateFormat) {
    39→      case 'long':
    40→        return `${monthNames[month]} ${day}, ${year}`;
    41→      case 'iso':
    42→        return `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    43→      case 'short':
    44→        return `${monthNames[month].substring(0, 3)} ${day}, ${year}`;
    45→      default:
    46→        return `${monthNames[month]} ${day}, ${year}`;
    47→    }
    48→  }, [today, dailyNotes.dateFormat]);
    49→
    50→  const handleToggleEnabled = () => {
    51→    setDailyNotesSettings({ enabled: !dailyNotes.enabled });
    52→  };
    53→
    54→  const handleDateFormatChange = (format: DailyNotesSettings['dateFormat']) => {
    55→    setDailyNotesSettings({ dateFormat: format });
    56→  };
    57→
    58→  const handleFolderChange = (folderId: string) => {
    59→    setDailyNotesSettings({ folderId: folderId === 'null' ? null : folderId });
    60→  };
    61→
    62→  const handleTemplateBlur = () => {
    63→    if (templateDraft !== dailyNotes.template) {
    64→      setDailyNotesSettings({ template: templateDraft });
    65→    }
    66→  };
    67→
    68→  return (
    69→    <div className="space-y-6">
    70→      {/* Header */}
    71→      <div>
    72→        <h3 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary mb-2 flex items-center gap-2">
    73→          <Calendar className="w-5 h-5" />
    74→          Daily Notes
    75→        </h3>
    76→        <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
    77→          Automatic daily notes inspired by Obsidian, Roam Research, and Logseq. Quick-capture thoughts, events, and learnings with a single click.
    78→        </p>
    79→      </div>
    80→
    81→      {/* Enable/Disable */}
    82→      <div className="flex items-center justify-between p-4 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-lg">
    83→        <div>
    84→          <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
    85→            Enable Daily Notes
    86→          </label>
    87→          <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
    88→            Quick access to today's note (Ctrl/Cmd + D)
    89→          </p>
    90→        </div>
    91→        <button
    92→          onClick={handleToggleEnabled}
    93→          className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${
    94→            dailyNotes.enabled
    95→              ? 'bg-accent-cyan'
    96→              : 'bg-border-light dark:bg-border-dark'
    97→          }`}
    98→          role="switch"
    99→          aria-checked={dailyNotes.enabled}
   100→        >
   101→          <span
   102→            className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
   103→              dailyNotes.enabled ? 'translate-x-6' : 'translate-x-1'
   104→            }`}
   105→          />
   106→        </button>
   107→      </div>
   108→
   109→      {dailyNotes.enabled && (
   110→        <>
   111→          {/* Date Format Selection */}
   112→          <div>
   113→            <label className="block text-sm font-medium text-text-light-primary dark:text-text-dark-primary mb-2">
   114→              Date Format
   115→            </label>
   116→            <div className="grid grid-cols-3 gap-2">
   117→              <button
   118→                onClick={() => handleDateFormatChange('long')}
   119→                className={`px-4 py-3 rounded-lg text-sm font-medium transition-colors ${
   120→                  dailyNotes.dateFormat === 'long'
   121→                    ? 'bg-accent-cyan text-white'
   122→                    : 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary hover:bg-border-light dark:hover:bg-border-dark'
   123→                }`}
   124→              >
   125→                Long
   126→              </button>
